module ethernet_mac_controller (
    input wire clk,
    input wire reset,
    input wire transmit,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);

    reg [7:0] data_cache;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_cache <= 8'b0;
            data_out <= 8'b0;
        end else if (transmit) begin
            data_cache <= data_in;
        end else begin
            data_out <= data_cache;
        end
    end
endmodule
